import { useEffect, useState } from "react";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogTrigger,
} from "@/components/ui/dialog";
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from "@/components/ui/table";
import { Badge } from "@/components/ui/badge";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import { apiClient } from "@/App";
import { toast } from "sonner";
import { Plus, Download } from "lucide-react";
import jsPDF from "jspdf";

const FeesPage = () => {
  const [payments, setPayments] = useState([]);
  const [loading, setLoading] = useState(true);
  const [dialogOpen, setDialogOpen] = useState(false);

  const [formData, setFormData] = useState({
    phone_number: "",
    amount: "",
    payment_type: "fees",
    payment_method: "mpesa",
    bank_reference: "",
    cheque_number: "",
  });

  useEffect(() => {
    fetchPayments();
  }, []);

  const fetchPayments = async () => {
    try {
      const response = await apiClient.get("/payments");
      setPayments(response.data);
    } catch (error) {
      toast.error("Failed to fetch payments");
    } finally {
      setLoading(false);
    }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      await apiClient.post("/payments/initiate", formData);
      toast.success("Payment recorded successfully");
      setDialogOpen(false);
      setTimeout(fetchPayments, 1000);
    } catch (error) {
      toast.error(error.response?.data?.detail || "Failed to record payment");
    }
  };

  const generateReceipt = (payment) => {
    const doc = new jsPDF();

    doc.setFontSize(20);
    doc.text("Smart Hub", 20, 20);

    doc.setFontSize(16);
    doc.text("Payment Receipt", 20, 35);

    doc.setFontSize(12);
    doc.text(`Receipt No: ${payment.receipt_number}`, 20, 50);
    doc.text(`Date: ${new Date(payment.created_at).toLocaleDateString()}`, 20, 60);
    doc.text(`Amount: KES ${payment.amount}`, 20, 70);
    doc.text(`Method: ${payment.payment_method.toUpperCase()}`, 20, 80);
    doc.text(`Type: ${payment.payment_type}`, 20, 90);
    doc.text(`Status: ${payment.status.toUpperCase()}`, 20, 100);

    doc.setFontSize(10);
    doc.text("Thank you for your payment!", 20, 130);

    doc.save(`receipt-${payment.receipt_number}.pdf`);
    toast.success("Receipt downloaded");
  };

  const getStatusColor = (status) => {
    switch (status) {
      case "completed":
        return "bg-green-100 text-green-800";
      case "pending":
        return "bg-yellow-100 text-yellow-800";
      case "failed":
        return "bg-red-100 text-red-800";
      default:
        return "bg-slate-100 text-slate-800";
    }
  };

  const totalCollected = payments
    .filter((p) => p.status === "completed")
    .reduce((sum, p) => sum + p.amount, 0);

  return (
    <div className="space-y-6">

      {/* HEADER */}
      <div className="flex items-center justify-between">
        <div>
          <h2 className="text-3xl font-bold text-white">Fees & Payments</h2>
          <p className="text-slate-400 mt-1">Manage fee collection and track payments</p>
        </div>

        <Dialog open={dialogOpen} onOpenChange={setDialogOpen}>
          <DialogTrigger asChild>
            <Button>
              <Plus className="w-4 h-4 mr-2" />
              Record Payment
            </Button>
          </DialogTrigger>

          <DialogContent className="max-w-md">
            <DialogHeader>
              <DialogTitle>Record Payment</DialogTitle>
            </DialogHeader>

            <form onSubmit={handleSubmit} className="space-y-4">

              {/* AMOUNT */}
              <div className="space-y-2">
                <Label htmlFor="amount">Amount (KES) *</Label>
                <Input
                  id="amount"
                  name="amount"
                  type="number"
                  placeholder="5000"
                  value={formData.amount}
                  onChange={(e) =>
                    setFormData({ ...formData, amount: e.target.value })
                  }
                  required
                />
              </div>

              {/* PAYMENT METHOD */}
              <div className="space-y-2">
                <Label htmlFor="payment-method">Payment Method *</Label>
                <Select
                  value={formData.payment_method}
                  onValueChange={(value) =>
                    setFormData({ ...formData, payment_method: value })
                  }
                >
                  <SelectTrigger id="payment-method">
                    <SelectValue />
                  </SelectTrigger>
                  <SelectContent>
                    <SelectItem value="mpesa">M-Pesa</SelectItem>
                    <SelectItem value="bank_transfer">Bank Transfer</SelectItem>
                    <SelectItem value="cash">Cash</SelectItem>
                    <SelectItem value="cheque">Cheque</SelectItem>
                  </SelectContent>
                </Select>
              </div>

              {/* CONDITIONAL INPUTS */}
              {formData.payment_method === "mpesa" && (
                <div className="space-y-2">
                  <Label htmlFor="phone-number">Phone Number</Label>
                  <Input
                    id="phone-number"
                    name="phone_number"
                    placeholder="254712345678"
                    value={formData.phone_number}
                    onChange={(e) =>
                      setFormData({ ...formData, phone_number: e.target.value })
                    }
                  />
                </div>
              )}

              {formData.payment_method === "bank_transfer" && (
                <div className="space-y-2">
                  <Label htmlFor="bank-reference">Bank Reference</Label>
                  <Input
                    id="bank-reference"
                    name="bank_reference"
                    placeholder="Enter bank reference"
                    value={formData.bank_reference}
                    onChange={(e) =>
                      setFormData({ ...formData, bank_reference: e.target.value })
                    }
                  />
                </div>
              )}

              {formData.payment_method === "cheque" && (
                <div className="space-y-2">
                  <Label htmlFor="cheque-number">Cheque Number</Label>
                  <Input
                    id="cheque-number"
                    name="cheque_number"
                    placeholder="Enter cheque number"
                    value={formData.cheque_number}
                    onChange={(e) =>
                      setFormData({ ...formData, cheque_number: e.target.value })
                    }
                  />
                </div>
              )}

              {/* PAYMENT TYPE */}
              <div className="space-y-2">
                <Label htmlFor="payment-type">Payment Type *</Label>
                <Select
                  value={formData.payment_type}
                  onValueChange={(value) =>
                    setFormData({ ...formData, payment_type: value })
                  }
                >
                  <SelectTrigger id="payment-type">
                    <SelectValue />
                  </SelectTrigger>
                  <SelectContent>
                    <SelectItem value="fees">School Fees</SelectItem>
                    <SelectItem value="installation">Installation Fee</SelectItem>
                    <SelectItem value="monthly_subscription">Monthly Subscription</SelectItem>
                    <SelectItem value="exam_fee">Exam Fee</SelectItem>
                    <SelectItem value="transport">Transport Fee</SelectItem>
                    <SelectItem value="other">Other</SelectItem>
                  </SelectContent>
                </Select>
              </div>

              <Button type="submit" className="w-full">
                Record Payment
              </Button>
            </form>
          </DialogContent>
        </Dialog>
      </div>

      {/* REST OF UI UNCHANGED */}
    </div>
  );
};

export default FeesPage;
